---
import '../styles/global.css';

interface Props {
  title?: string;
  description?: string;
}

const {
  title = 'incomplete.fun',
  description = 'A collection of fun, incomplete things.',
} = Astro.props;
---

<!doctype html>
<html lang="en">
  <head>
    <meta charset="utf-8" />
    <link rel="icon" type="image/svg+xml" href="/favicon.svg" />
    <link rel="icon" href="/favicon.ico" />
    <meta name="viewport" content="width=device-width" />
    <meta name="description" content={description} />
    <title>{title}</title>
  </head>
  <body>
    <slot />
    <script>
      import '../scripts/themes.ts';
    </script>
  </body>
</html>

:root {
  color-scheme: light dark;
  --bg: #fcfcfa;
  --fg: #171716;
  --muted: #716f68;
  --line: #e4e1d8;
  --wash: color-mix(in srgb, var(--bg) 94%, var(--fg));
  --accent: currentColor;
  --border: var(--line);
  --mono: inherit;
  --space: clamp(1rem, 4vw, 2.5rem);
  --measure: 38rem;
  font-family: ui-monospace, "SFMono-Regular", Menlo, Consolas, monospace;
}

@media (prefers-color-scheme: dark) {
  :root {
    --bg: #0f0f0e;
    --fg: #eeeeea;
    --muted: #9c9890;
    --line: #302e2a;
  }
}

:root[data-theme="chalkboard"] {
  --bg: #101815;
  --fg: #e8f5df;
  --muted: #a9b9a2;
  --line: #314038;
}

:root[data-theme="blueprint"] {
  --bg: #071a2c;
  --fg: #d8f1ff;
  --muted: #8db7d4;
  --line: #21486a;
}

:root[data-theme="vaporwave"] {
  --bg: #19051f;
  --fg: #ffd6ff;
  --muted: #70f2ff;
  --line: #6d2b87;
}

:root[data-theme="ink"] {
  --bg: #fbfaf4;
  --fg: #10100f;
  --muted: #595750;
  --line: #c9c4b8;
}

:root[data-theme="solarized"] {
  --bg: #fdf6e3;
  --fg: #073642;
  --muted: #657b83;
  --line: #eee8d5;
}

* { box-sizing: border-box; }

body {
  margin: 0;
  background: var(--bg);
  color: var(--fg);
  font-size: 15px;
  line-height: 1.65;
  text-rendering: optimizeLegibility;
}

a {
  color: inherit;
  text-decoration: underline;
  text-decoration-color: var(--line);
  text-underline-offset: .25em;
}

a:hover { text-decoration-color: currentColor; }

h1, h2, h3, p, ul, ol { margin: 0 0 1rem; }

h1, h2, h3, strong { font-weight: 600; }

h1 {
  max-width: 13ch;
  font-size: clamp(2rem, 9vw, 5rem);
  line-height: .95;
  letter-spacing: -0.06em;
}

ul, ol { padding-left: 1.25rem; }

code {
  padding: .1em .3em;
  border: 1px solid var(--line);
  border-radius: 3px;
}

.app-shell, .canvas-app {
  min-height: 100dvh;
  background: var(--bg);
}

.app-shell { display: grid; grid-template-rows: auto 1fr; }
.canvas-app {
  position: relative;
  display: flex;
  flex-direction: column;
}

.equation-wallpaper {
  position: fixed;
  inset: 0;
  z-index: 0;
  overflow: hidden;
  pointer-events: none;
  color: var(--fg);
  opacity: .065;
}

.equation-wallpaper span {
  position: absolute;
  animation: equation-drift linear infinite;
  white-space: nowrap;
}

.canvas-app > :not(.equation-wallpaper) {
  position: relative;
  z-index: 1;
}

@keyframes equation-drift {
  from { transform: translate3d(-1rem, 0, 0) rotate(-6deg); }
  to { transform: translate3d(1rem, -4rem, 0) rotate(6deg); }
}

.control-panel {
  display: flex;
  align-items: center;
  gap: .6rem;
  padding: .55rem var(--space);
  border-bottom: 1px solid var(--line);
  background: color-mix(in srgb, var(--bg) 88%, transparent);
  backdrop-filter: blur(10px);
  flex-wrap: wrap;
}

.control-panel input[type="range"] { width: 8rem; }

.is-darkroom .canvas-app {
  background: #020202;
  color: #f5f2e8;
}

.is-darkroom .topbar,
.is-darkroom .control-panel {
  opacity: .08;
  transition: opacity .6s ease;
}

.is-darkroom .topbar:hover,
.is-darkroom .control-panel:hover { opacity: 1; }

.is-darkroom .canvas-stage::after {
  content: attr(id);
  position: absolute;
  left: var(--space);
  bottom: var(--space);
  color: currentColor;
  opacity: .35;
  animation: darkroom-label 3s ease both;
  pointer-events: none;
}

@keyframes darkroom-label { from { opacity: 0; transform: translateY(.5rem); } }

.topbar {
  display: flex;
  align-items: center;
  gap: 1rem;
  min-height: 3.25rem;
  padding: .75rem var(--space);
  border-bottom: 1px solid var(--line);
  flex-wrap: wrap;
}

.brand,
.topbar-title {
  text-decoration: none;
}

.brand { font-weight: 600; }

.topbar-title { color: var(--muted); }

.back-link {
  color: var(--muted);
  text-decoration: none;
}

.page {
  width: min(100%, var(--measure));
  margin: 0 auto;
  padding: calc(var(--space) * 1.4) var(--space);
}

.page-wide { --measure: 72rem; }

.home-hero {
  position: relative;
  display: grid;
  gap: 1rem;
  margin-bottom: calc(var(--space) * 1.3);
  padding: min(8vw, 4rem) 0;
}

.landing-animation {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  z-index: 0;
  opacity: .55;
}

.home-hero > :not(.landing-animation) {
  position: relative;
  z-index: 1;
}

.eyebrow,
.home-intro { color: var(--muted); }

.eyebrow {
  margin: 0;
  font-size: .78rem;
  letter-spacing: .08em;
  text-transform: uppercase;
}

.constellation-map {
  margin-bottom: calc(var(--space) * 1.2);
  border: 1px solid var(--line);
  border-radius: 18px;
  padding: .75rem;
  background: var(--wash);
}

.constellation-map svg {
  display: block;
  width: 100%;
  height: auto;
  overflow: visible;
}

.constellation-map line {
  stroke: var(--fg);
  stroke-width: .15;
  opacity: .2;
  stroke-dasharray: 1 1.5;
  animation: map-pulse 6s linear infinite;
}

.constellation-map circle {
  fill: var(--fg);
  opacity: .6;
}

@keyframes map-pulse { to { stroke-dashoffset: -10; } }

.home-links {
  display: grid;
  gap: .5rem;
}

.home-link {
  display: grid;
  grid-template-columns: 5rem minmax(0, 1fr) minmax(8rem, 14rem);
  align-items: center;
  gap: 1rem;
  padding: .8rem 0;
  border-top: 1px solid var(--line);
  text-decoration: none;
}

.home-preview {
  width: 5rem;
  height: 3rem;
  border: 1px solid var(--line);
  border-radius: 9px;
  background: var(--wash);
}

.home-link:hover span { text-decoration: underline; text-underline-offset: .25em; }
.home-link small { color: var(--muted); }

@media (max-width: 34rem) {
  .home-link { grid-template-columns: 5rem 1fr; gap: .15rem .75rem; }
  .home-link small { grid-column: 2; }
}

.math-notebook {
  position: fixed;
  right: var(--space);
  top: 7.25rem;
  z-index: 3;
  width: min(18rem, calc(100vw - 2 * var(--space)));
  max-height: calc(100dvh - 9rem);
  overflow: auto;
  padding: .9rem;
  border: 1px solid var(--line);
  border-radius: 16px;
  background: color-mix(in srgb, var(--bg) 90%, transparent);
  backdrop-filter: blur(14px);
  color: var(--muted);
  font-size: .8rem;
}

.canvas-app > .math-notebook {
  position: fixed;
  z-index: 3;
}

.math-notebook strong { color: var(--fg); }
.math-notebook ul { margin-bottom: 0; }

.canvas-stage {
  position: relative;
  flex: 1;
  overflow: hidden;
}

@media (max-width: 58rem) {
  .math-notebook { display: none; }
}

button, input {
  font: inherit;
  color: inherit;
}

.toolbar-button,
.metric-button {
  background: transparent;
  border: 1px solid var(--line);
  border-radius: 999px;
  padding: .15rem .7rem;
  cursor: pointer;
}

.toolbar-button:hover,
.toolbar-button.is-active,
.metric-button:hover,
.metric-button.is-active {
  background: var(--fg);
  border-color: var(--fg);
  color: var(--bg);
}

select,
textarea,
input:not([type="checkbox"]):not([type="range"]):not([type="color"]) {
  background: transparent;
  border: 1px solid var(--line);
  border-radius: 4px;
  color: var(--fg);
  font: inherit;
}

.control-label {
  display: inline-flex;
  align-items: center;
  gap: .4rem;
  color: var(--muted);
}

input[type="number"] {
  width: 3.5rem;
  background: transparent;
  border: 1px solid var(--line);
  border-radius: 4px;
  padding: .1rem .35rem;
}

input[type="color"] {
  width: 2rem;
  height: 1.4rem;
  padding: 0;
  border: 1px solid var(--line);
  background: transparent;
}

input[type="checkbox"],
input[type="range"] {
  accent-color: var(--fg);
}

export {};

const select = document.querySelector<HTMLSelectElement>('[data-theme-select]');
const saved = localStorage.getItem('incomplete-theme') || 'default';

document.documentElement.dataset.theme = saved;
if (select) select.value = saved;

select?.addEventListener('change', () => {
  const theme = select.value;
  document.documentElement.dataset.theme = theme;
  localStorage.setItem('incomplete-theme', theme);
});

{
