:root {
  color-scheme: light dark;
  --bg: #fcfcfa;
  --fg: #171716;
  --muted: #716f68;
  --line: #e4e1d8;
  --wash: color-mix(in srgb, var(--bg) 94%, var(--fg));
  --accent: currentColor;
  --border: var(--line);
  --mono: inherit;
  --space: clamp(1rem, 4vw, 2.5rem);
  --measure: 38rem;
  font-family: ui-monospace, "SFMono-Regular", Menlo, Consolas, monospace;
}

@media (prefers-color-scheme: dark) {
  :root {
    --bg: #0f0f0e;
    --fg: #eeeeea;
    --muted: #9c9890;
    --line: #302e2a;
  }
}

:root[data-theme="chalkboard"] {
  --bg: #101815;
  --fg: #e8f5df;
  --muted: #a9b9a2;
  --line: #314038;
}

:root[data-theme="blueprint"] {
  --bg: #071a2c;
  --fg: #d8f1ff;
  --muted: #8db7d4;
  --line: #21486a;
}

:root[data-theme="vaporwave"] {
  --bg: #19051f;
  --fg: #ffd6ff;
  --muted: #70f2ff;
  --line: #6d2b87;
}

:root[data-theme="ink"] {
  --bg: #fbfaf4;
  --fg: #10100f;
  --muted: #595750;
  --line: #c9c4b8;
}

:root[data-theme="solarized"] {
  --bg: #fdf6e3;
  --fg: #073642;
  --muted: #657b83;
  --line: #eee8d5;
}

